fn quicksort(arr: &mut [i32]) {
    if arr.len() <= 1 {
        return;
    }
    let pivot = arr[arr.len() / 2];
    let mut left = arr.iter().filter(|x| **x < pivot).copied().collect::<Vec<_>>();
    let mut middle = arr.iter().filter(|x| **x == pivot).copied().collect::<Vec<_>>();
    let mut right = arr.iter().filter(|x| **x > pivot).copied().collect::<Vec<_>>();
    quicksort(&mut left);
    quicksort(&mut right);
    let mut i = 0;
    let mut j = 0;
    let mut k = 0;
    while i < left.len() || j < middle.len() || k < right.len() {
        if i < left.len() && (j == middle.len() || left[i] < right[k]) {
            arr[i + j + k] = left[i];
            i += 1;
        } else if j < middle.len() && (i == left.len() || middle[j] <= right[k]) {
            arr[i + j + k] = middle[j];
            j += 1;
        } else {
            arr[i + j + k] = right[k];
            k += 1;
        }
    }
}

fn main() {
